#!/usr/bin/env python3
# -*- coding: utf-8 -*-
r"""
PANDA SNACK - Corrections Phase 1+2+3 V2 (27 avril 2026)

CHANGEMENTS V2 (suite audit):
  - auth/reset: utilise le helper createClient projet + fix boucle useEffect
  - auth/confirm: cas special type=recovery -> /auth/reset
  - cancel-order: increment total_credited_cents sur refund
  - order-item: count nullable safeguarded + total_credited_cents fix
  - webhook: idempotence separee recharge / order
  - RechargerClient + Navbar + webhook: vrais caracteres euro/a/e (pas backslash-uXXXX)
  - commander/page: select * propre (pas de doublon last_recharge_cents)

PHASES COUVERTES:
  Phase 1 - Heure limite de commande unifiee (orders_cutoff_at DB)
  Phase 2 - Fixes auth + recharger
  Phase 3 - Wallet pricing (UI uniquement, prix reel CommanderClient = TODO session dediee)

MIGRATION DB (deja appliquee via MCP):
  - wallets.last_recharge_cents (integer default 0)
  - enum credit_stripe ajoute (securite)

USAGE: cd ~/Desktop/pandasnack && python3 write_files.py
"""

import base64, os, sys

if not os.path.exists("src/app"):
    print("ERREUR: Lance ce script depuis ~/Desktop/pandasnack")
    sys.exit(1)

FILES = {
    "src/app/auth/reset/page.tsx": "",
    "src/app/auth/confirm/route.ts": "",
    "src/app/api/checkout/route.ts": "",
    "src/app/api/save-order/route.ts": "",
    "src/app/api/cancel-order/route.ts": "",
    "src/app/api/order-item/route.ts": "",
    "src/app/api/stripe/webhook/route.ts": "",
    "src/app/commander/page.tsx": "",
    "src/app/recharger/page.tsx": "",
    "src/app/recharger/RechargerClient.tsx": "",
    "src/app/mes-commandes/page.tsx": "",
    "src/app/mes-commandes/MesCommandesClient.tsx": "",
    "src/components/Navbar.tsx": "",
}

written = 0
for path, b64 in FILES.items():
    parent = os.path.dirname(path)
    if parent and os.path.isfile(parent):
        os.remove(parent)
    os.makedirs(parent, exist_ok=True)
    data = base64.b64decode(b64)
    with open(path, "wb") as f:
        f.write(data)
    print(f"  OK {path} ({len(data)} bytes)")
    written += 1

print(f"\n{written} fichiers ecrits. Pret pour git add + commit + push.")
